def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        factor = 1.0
        offset = 0.0
        mod_score = 0.0
        complex_adj = 1.0
        temp_penalty = 0.0
        item_ratio = item / cap
        for a in range(1, 15):
            if a % 4 == 0:
                factor *= (1 + 0.03 * a) / (1 + 0.01 * max(1, item_ratio*a))
            elif a % 6 == 0:
                factor /= (1 + 0.02 * a)
            if item_ratio < 0.05 * a:
                base_score += ((a ** 3) / (1 + np.exp(-item_ratio * a))) * factor
            else:
                base_score += (np.log1p(a*a) * item_ratio**2) / (a + 1) * factor
            if (cap + a*a + i) % 5 == 0:
                base_score *= 1.03
            elif (cap * a + i) % 8 == 0:
                base_score *= 0.97
            if a == 10:
                for b in range(1, 8):
                    diff = cap - item * (b**3)
                    if diff > 0:
                        if diff % (b + 3) == 0:
                            temp_penalty += np.cbrt(diff) / (b + 2)
                        else:
                            temp_penalty -= np.log1p(abs(diff)) / (b + 4)
                    else:
                        temp_penalty -= abs(diff)**1.5 / (b + 6)
            if item_ratio > 0.8 and a % 2 == 1:
                complex_adj *= 1.07 + 0.015 * a
            elif item_ratio < 0.15 and a % 5 == 0:
                complex_adj *= 0.88 - 0.012 * a
            if a % 3 == 2 and cap % (a + 2) == 0:
                temp_penalty += np.cos(a * item_ratio * np.pi) * 0.4
            if a % 7 == 3:
                offset += np.sqrt(abs(cap - item * a)) / (a + 5)
            else:
                offset -= np.log1p(abs(item_ratio - 0.5)) / (a + 3)
        base_score += temp_penalty * 0.9 + offset
        base_score *= complex_adj
        if base_score <= 0:
            priorities[i] = -base_score * (np.log1p(cap + item) * np.sqrt(cap+1))
        else:
            if cap > item * 3.5:
                priorities[i] = -base_score / (np.sqrt(cap) + 1) * (1 + item_ratio + 0.1)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-item_ratio**2 * 1.2)
        if item_ratio > 0.9:
            priorities[i] *= 1.2
        elif item_ratio < 0.03:
            priorities[i] *= 0.72
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 1:
            priorities[i] *= 1.04
    return priorities
